func summarizeSearchResults(results []json.RawMessage) []json.RawMessage {
	summaries := make([]json.RawMessage, 0, len(results))
	for _, result := range results {
		summaries = append(summaries, summarizeSearchMatch(result))
	}
	return summaries
}

